import {useState} from "react";
import axios from "axios";

export default function CourseForm({setData}){

const [skills,setSkills]=useState("");

const [goal,setGoal]=useState("");

const [loading,setLoading]=useState(false);

async function analyze(){

try{

setLoading(true);

const res =
await axios.post(

"http://localhost:5001/api/recommend",

{
skills,
goal
}

);

setData(res.data);

}
catch(error){

console.log(error);

alert("Backend error");

}

setLoading(false);

}

return(

<div className="form">

<input

placeholder="Enter skills (React, Node)"

onChange={e=>
setSkills(e.target.value)
}

/>

<input

placeholder="Career goal"

onChange={e=>
setGoal(e.target.value)
}

/>

<button

className="analyzeBtn"

onClick={analyze}

disabled={loading}

>

{loading ? (

<div className="loaderRow">

<div className="spinner"/>

Analyzing...

</div>

):

"Generate Roadmap"

}

</button>

</div>

);

}
